import{_ as e,o as l,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"การตั้งค่าอัปโหลด","description":"","frontmatter":{},"headers":[],"relativePath":"th-TH/upload/index.md","filePath":"th-TH/upload/index.md","lastUpdated":1781962217000}'),o={name:"th-TH/upload/index.md"};function t(n,a,d,h,s,c){return l(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="การตั้งค่าอัปโหลด" tabindex="-1">การตั้งค่าอัปโหลด <a class="header-anchor" href="#การตั้งค่าอัปโหลด" aria-label="Permalink to &quot;การตั้งค่าอัปโหลด&quot;">​</a></h1><p>ส่วนนี้จัดเรียงตามลำดับ channel เดียวกับหน้า System Settings เพื่อให้คุณไปยัง storage provider ที่ต้องตั้งค่าได้ทันที</p><h2 id="โครงสร้างของส่วนนี้" tabindex="-1">โครงสร้างของส่วนนี้ <a class="header-anchor" href="#โครงสร้างของส่วนนี้" aria-label="Permalink to &quot;โครงสร้างของส่วนนี้&quot;">​</a></h2><ul><li>แต่ละ provider มีหน้าแยกของตัวเอง การแยก upload channel ทั้ง 13 แบบออกจากกันช่วยให้ทำตามขั้นตอนได้ง่ายขึ้น</li><li>รูปหน้าจอเก็บไว้ใน <code>../../image/upload/provider-name/</code> และอ้างอิงแบบ local จากแต่ละหน้า</li><li>เอกสารภาษาไทยถูกปรับให้เข้ากับการใช้งานจริง โดยยังคงชื่อ field ให้ใกล้กับ UI ของผลิตภัณฑ์เท่าที่เหมาะสม</li></ul><h2 id="รายการ-channel" tabindex="-1">รายการ Channel <a class="header-anchor" href="#รายการ-channel" aria-label="Permalink to &quot;รายการ Channel&quot;">​</a></h2><ul><li><a href="./telegram">Telegram</a></li><li><a href="./cloudflare-r2">Cloudflare R2</a></li><li><a href="./s3">S3</a></li><li><a href="./webdav">WebDAV</a></li><li><a href="./discord">Discord</a></li><li><a href="./huggingface">Hugging Face</a></li><li><a href="./github-releases">GitHub Releases</a></li><li><a href="./gitlab-packages">GitLab Packages</a></li><li><a href="./onedrive">OneDrive</a></li><li><a href="./google-drive">Google Drive</a></li><li><a href="./dropbox">Dropbox</a></li><li><a href="./yandex">Yandex</a></li><li><a href="./pcloud">pCloud</a></li></ul><h2 id="บทนี้ครอบคลุมอะไรบ้าง" tabindex="-1">บทนี้ครอบคลุมอะไรบ้าง <a class="header-anchor" href="#บทนี้ครอบคลุมอะไรบ้าง" aria-label="Permalink to &quot;บทนี้ครอบคลุมอะไรบ้าง&quot;">​</a></h2><ul><li>วิธีเพิ่ม upload channel แต่ละประเภท</li><li>ต้องเตรียม credentials, keys หรือ IDs อะไรก่อนเพิ่ม channel</li><li>วิธีตรวจสอบว่า channel พร้อมใช้อัปโหลดแล้วหรือยัง</li></ul><p>รายละเอียด troubleshooting, quota strategy และ best practices จะอธิบายแยกไว้ในหน้าที่เกี่ยวข้อง</p>',9)])])}const f=e(o,[["render",t]]);export{p as __pageData,f as default};
